// Semafor veri yapisi
typedef struct {
    int value;
    struct process *list;  // Bekleme kuyrugu
} semaphore;

// wait() - mesgul beklemesiz
wait(semaphore *S) {
    S->value--;
    if (S->value < 0) {
        add this process to S->list;
        block();   // Sureci bekleme durumuna al
    }
}

// signal() - mesgul beklemesiz
signal(semaphore *S) {
    S->value++;
    if (S->value <= 0) {
        remove a process P from S->list;
        wakeup(P); // Sureci hazir durumuna al
    }
}

